#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define fp double
#define NUMBER_PAR_PER_BOX 100
#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct {
    fp x, y, z;
} THREE_VECTOR;

typedef struct {
    fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str {
    int x, y, z;
    int number;
    long offset;
} nei_str;

typedef struct box_str {
    int x, y, z;
    int number;
    long offset;
    int nn;
    nei_str nei[26];
} box_str;

typedef struct par_str {
    fp alpha;
} par_str;

typedef struct dim_str {
    int cur_arg;
    int arch_arg;
    int cores_arg;
    int boxes1d_arg;
    long number_boxes;
    long box_mem;
    long space_elem;
    long space_mem;
    long space_mem2;
} dim_str;

kernel void kernel_gpu_opencl(
    par_str par,
    dim_str dim,
    const global box_str* box,
    const global FOUR_VECTOR* rv,
    const global fp* qv,
    global FOUR_VECTOR* fv)
{
    int l = get_global_id(0) / NUMBER_THREADS;
    int tid = get_global_id(0) % NUMBER_THREADS;

    if (l >= dim.number_boxes) return;

    fp alpha = par.alpha;
    fp a2 = 2.0 * alpha * alpha;

    long first_i = box[l].offset;

    // Use local memory for rA and fA to reduce global accesses and allow accumulation
    // Define local arrays explicitly to avoid potential struct copy issues in some OpenCL implementations
    local fp rA_v[NUMBER_PAR_PER_BOX];
    local fp rA_x[NUMBER_PAR_PER_BOX];
    local fp rA_y[NUMBER_PAR_PER_BOX];
    local fp rA_z[NUMBER_PAR_PER_BOX];

    local fp fA_v[NUMBER_PAR_PER_BOX];
    local fp fA_x[NUMBER_PAR_PER_BOX];
    local fp fA_y[NUMBER_PAR_PER_BOX];
    local fp fA_z[NUMBER_PAR_PER_BOX];

    // Load particle data for this box into local memory
    for (int i = tid; i < NUMBER_PAR_PER_BOX; i += NUMBER_THREADS) {
        FOUR_VECTOR tmp = rv[first_i + i];
        rA_v[i] = tmp.v;
        rA_x[i] = tmp.x;
        rA_y[i] = tmp.y;
        rA_z[i] = tmp.z;

        fA_v[i] = 0.0;
        fA_x[i] = 0.0;
        fA_y[i] = 0.0;
        fA_z[i] = 0.0;
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    // Process neighbors
    for (int k = 0; k < (1 + box[l].nn); k++) {
        int pointer;
        if (k == 0) {
            pointer = l;
        } else {
            pointer = box[l].nei[k-1].number;
        }

        long first_j = box[pointer].offset;

        // Iterate over particles in the current box (i) and neighbor box (j)
        // Total pairs = NUMBER_PAR_PER_BOX * NUMBER_PAR_PER_BOX = 10000
        // We distribute these pairs among the threads in the block.
        for (int idx = tid; idx < NUMBER_PAR_PER_BOX * NUMBER_PAR_PER_BOX; idx += NUMBER_THREADS) {
            int i = idx / NUMBER_PAR_PER_BOX;
            int j = idx % NUMBER_PAR_PER_BOX;

            FOUR_VECTOR rB = rv[first_j + j];
            fp qB = qv[first_j + j];

            fp r2 = rA_v[i] + rB.v - (rA_x[i]*rB.x + rA_y[i]*rB.y + rA_z[i]*rB.z);
            fp u2 = a2 * r2;
            fp vij = exp(-u2);
            fp fs = 2.0 * vij;

            fp dx = rA_x[i] - rB.x;
            fp dy = rA_y[i] - rB.y;
            fp dz = rA_z[i] - rB.z;

            fA_v[i] += qB * vij;
            fA_x[i] += qB * fs * dx;
            fA_y[i] += qB * fs * dy;
            fA_z[i] += qB * fs * dz;
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    // Write results back to global memory
    for (int i = tid; i < NUMBER_PAR_PER_BOX; i += NUMBER_THREADS) {
        FOUR_VECTOR tmp = fv[first_i + i];
        tmp.v += fA_v[i];
        tmp.x += fA_x[i];
        tmp.y += fA_y[i];
        tmp.z += fA_z[i];
        fv[first_i + i] = tmp;
    }
}

